onChange.script:
	system.perspective.print("Selected station:%s"%self.view.params.SelectedStation)
	station=self.view.params.SelectedStation
	prefix=station[:2]
	if self.props.currentTabIndex==0:
		payload={'Station':prefix+'QG01'}
		system.perspective.sendMessage('Station_Select',payload,scope = 'page')
		self.view.params.SelectedStation=prefix+'QG01'
